<script setup>import{onMounted,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),users=ref([]),search=ref(''),message=ref('');async function load(){users.value=(await axios.get('/api/users')).data}onMounted(load);async function role(u){await axios.put(`/api/users/${u.id}/role`,{role:u.role});message.value='Role updated.'}async function remove(u){if(u.id===auth.user.id)return;if(confirm(`Remove access for ${u.name}?`)){try{await axios.delete(`/api/users/${u.id}`);await load()}catch(e){message.value=e.response?.data?.message||'Unable to remove account.'}}}</script>
<template><PageHeader title="User access" subtitle="Manage staff and customer roles"/><p v-if="message" class="notice">{{message}}</p><section class="panel"><div class="filters"><label>Search users<input v-model="search" placeholder="Name or email"></label></div><div class="table-wrap"><table><thead><tr><th>User</th><th>Email</th><th>Role</th><th>Status</th><th>Action</th></tr></thead><tbody><tr v-for="u in users.filter(x=>(x.name+x.email).toLowerCase().includes(search.toLowerCase()))" :key="u.id"><td><strong>{{u.name}}</strong></td><td>{{u.email}}</td><td><select v-model="u.role" :disabled="u.id===auth.user.id" @change="role(u)"><option>admin</option><option>assistant</option><option>cashier</option><option>user</option></select></td><td><span class="tag" :class="{warn:!u.is_active}">{{u.is_active?'Active':'Disabled'}}</span></td><td><button class="btn tiny danger" :disabled="u.id===auth.user.id" @click="remove(u)">{{u.id===auth.user.id?'Current account':'Remove access'}}</button></td></tr></tbody></table></div></section></template>
